def format_context_summary(ctx: OptimizedContext) -> str:
    """Format context optimization summary for display."""
    lines = [
        f"Sets: {', '.join(ctx.sets)}",
        f"Estimated tokens: {ctx.estimated_tokens:,}",
        f"Positioning: {ctx.positioning}",
    ]

    if ctx.critical_files:
        lines.append(f"Critical files: {len(ctx.critical_files)}")

    if ctx.truths:
        lines.append("Truths: loaded")

    if ctx.budget_warning:
        lines.append(f"WARNING: Exceeds {get_hard_cap():,} token budget!")

    return "\n".join(lines)

def _match_purpose(keywords: List[str]) -> Tuple[Optional[str], float]:
    """Match keywords to π₂ PURPOSE field."""
    for kw in keywords:
        if kw in QUERY_PURPOSE_KEYWORDS:
            return QUERY_PURPOSE_KEYWORDS[kw], 0.9

    # Partial matching
    for kw in keywords:
        for pattern, purpose in QUERY_PURPOSE_KEYWORDS.items():
            if pattern in kw or kw in pattern:
                return purpose, 0.6

    return None, 0.0

def _match_layer(keywords: List[str]) -> Tuple[Optional[str], float]:
    """Match keywords to architecture layer."""
    for kw in keywords:
        if kw in QUERY_LAYER_KEYWORDS:
            return QUERY_LAYER_KEYWORDS[kw], 0.9

    # Partial matching
    for kw in keywords:
        for pattern, layer in QUERY_LAYER_KEYWORDS.items():
            if pattern in kw or kw in pattern:
                return layer, 0.6

    return None, 0.0

def _match_direction(keywords: List[str]) -> EdgeDirection:
    """Match keywords to graph traversal direction."""
    for kw in keywords:
        if kw in QUERY_DIRECTION_KEYWORDS:
            return QUERY_DIRECTION_KEYWORDS[kw]
    return EdgeDirection.BOTH

def _match_roles(keywords: List[str]) -> List[str]:
    """Match keywords to DDD roles."""
    matched = []
    for kw in keywords:
        kw_lower = kw.lower()
        for roles in ROLE_CLUSTERS.values():
            for role in roles:
                if kw_lower in role.lower() or role.lower() in kw_lower:
                    if role not in matched:
                        matched.append(role)
    return matched

def _purpose_to_sets(purpose: str) -> List[str]:
    """Map PURPOSE to analysis sets."""
    mapping = {
        "Retrieve": ["pipeline", "data_access"],
        "Persist": ["infrastructure", "data_access"],
        "Transform": ["pipeline", "classifiers"],
        "Compute": ["pipeline", "algorithms"],
        "Validate": ["validators", "constraints"],
        "Coordinate": ["services", "orchestration"],
        "Transport": ["gateways", "infrastructure"],
        "Present": ["presentation", "viz_core"],
    }
    return mapping.get(purpose, ["pipeline"])

def _layer_to_sets(layer: str) -> List[str]:
    """Map architecture layer to analysis sets."""
    mapping = {
        "Interface": ["controllers", "api"],
        "Application": ["services", "pipeline"],
        "Core": ["domain", "entities", "theory"],
        "Infrastructure": ["infrastructure", "data_access"],
        "Test": ["tests"],
    }
    return mapping.get(layer, ["pipeline"])

def _determine_context_flow(targets: List[SemanticTarget]) -> str:
    """Determine if context flow is laminar (coherent) or turbulent (mixed)."""
    if not targets:
        return "turbulent"

    # Check purpose coherence
    purposes = [t.purpose for t in targets if t.purpose]
    if len(set(purposes)) <= 1:
        return "laminar"

    # Check layer coherence
    layers = [t.layer for t in targets if t.layer]
    if len(set(layers)) <= 2:
        # Adjacent layers are still laminar
        if len(layers) >= 2:
            layer_indices = [LAYER_ORDER.index(l) for l in layers if l in LAYER_ORDER]
            if layer_indices and max(layer_indices) - min(layer_indices) <= 1:
                return "laminar"

    return "turbulent"

def _determine_traversal_strategy(targets: List[SemanticTarget]) -> str:
    """Determine graph traversal strategy."""
    if not targets:
        return "exploratory"

    # If single focused target, use focused strategy
    if len(targets) == 1 and targets[0].confidence > 0.7:
        return "focused"

    # If multiple layers involved, use hierarchical
    layers = [t.layer for t in targets if t.layer]
    if len(set(layers)) > 1:
        return "hierarchical"

    return "exploratory"

def get_upstream_context(particle_id: str, graph_data: Dict) -> List[str]:
    """
    Get upstream context (providers, dependencies) for a particle.

    Traverses UPSTREAM_EDGES to find what this particle depends on.
    """
    if "edges" not in graph_data:
        return []

    upstream = []
    for edge in graph_data["edges"]:
        if edge.get("source") == particle_id and edge.get("type") in UPSTREAM_EDGES:
            upstream.append(edge.get("target"))
        elif edge.get("target") == particle_id and edge.get("type") in DOWNSTREAM_EDGES:
            upstream.append(edge.get("source"))

    return upstream

def get_downstream_context(particle_id: str, graph_data: Dict) -> List[str]:
    """
    Get downstream context (consumers, callers) for a particle.

    Traverses DOWNSTREAM_EDGES to find what depends on this particle.
    """
    if "edges" not in graph_data:
        return []

    downstream = []
    for edge in graph_data["edges"]:
        if edge.get("source") == particle_id and edge.get("type") in DOWNSTREAM_EDGES:
            downstream.append(edge.get("target"))
        elif edge.get("target") == particle_id and edge.get("type") in UPSTREAM_EDGES:
            downstream.append(edge.get("source"))

    return downstream

def format_semantic_match(match: SemanticMatch) -> str:
    """Format semantic match for display."""
    lines = [
        f"Query: {match.query[:80]}...",
        f"Strategy: {match.traversal_strategy} ({match.context_flow} flow)",
        f"Reasoning: {match.reasoning}",
    ]

    if match.targets:
        lines.append("Targets:")
        for t in match.targets:
            parts = []
            if t.purpose:
                parts.append(f"π₂={t.purpose}")
            if t.layer:
                parts.append(f"layer={t.layer}")
            if t.roles:
                parts.append(f"roles=[{','.join(t.roles[:3])}]")
            lines.append(f"  - {' '.join(parts)} (conf={t.confidence:.2f})")

    lines.append(f"Sets: {', '.join(match.suggested_sets)}")

    if match.suggested_files:
        lines.append(f"Files: {', '.join(match.suggested_files[:3])}")

    return "\n".join(lines)

def get_repo_id(repo_path: Path) -> Dict:
    """Get repository identification info."""
    try:
        commit = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True, text=True, cwd=repo_path
        ).stdout.strip()[:12]

        branch = subprocess.run(
            ["git", "rev-parse", "--abbrev-ref", "HEAD"],
            capture_output=True, text=True, cwd=repo_path
        ).stdout.strip()

        return {
            "commit": commit,
            "branch": branch,
            "timestamp": datetime.now().isoformat(),
            "version": REPOPACK_VERSION
        }
    except Exception:
        return {"commit": "unknown", "branch": "unknown", "timestamp": datetime.now().isoformat(), "version": REPOPACK_VERSION}

def get_file_tree(repo_path: Path, max_depth: int = 3, max_files: int = 200) -> str:
    """Get directory structure as tree string."""
    lines = []
    count = 0

    def walk(path: Path, prefix: str = "", depth: int = 0):
        nonlocal count
        if depth > max_depth or count > max_files:
            return

        try:
            entries = sorted(path.iterdir(), key=lambda x: (not x.is_dir(), x.name))
        except PermissionError:
            return

        dirs = [e for e in entries if e.is_dir() and not e.name.startswith('.')]
        files = [e for e in entries if e.is_file() and not e.name.startswith('.')]

        for d in dirs[:20]:  # Limit dirs per level
            lines.append(f"{prefix}{d.name}/")
            walk(d, prefix + "  ", depth + 1)

        for f in files[:30]:  # Limit files per level
            count += 1
            if count <= max_files:
                lines.append(f"{prefix}{f.name}")

    walk(repo_path)
    return "\n".join(lines[:max_files])

def get_hot_files(repo_path: Path, limit: int = 10) -> List[Dict]:
    """Get recently modified files with content."""
    try:
        result = subprocess.run(
            ["git", "diff", "--name-only", "HEAD~5", "HEAD"],
            capture_output=True, text=True, cwd=repo_path
        )
        files = result.stdout.strip().split("\n")[:limit]

        hot = []
        for f in files:
            if not f:
                continue
            path = repo_path / f
            if path.exists() and path.stat().st_size < 50000:  # Max 50KB
                try:
                    content = path.read_text(errors='ignore')[:10000]  # Max 10K chars
                    hot.append({"path": f, "content": content})
                except Exception:
                    pass
        return hot
    except Exception:
        return []

def get_cache_key(repo_path: Path) -> str:
    """Generate deterministic cache key for repo state."""
    repo_id = get_repo_id(Path(repo_path))

    # Check for uncommitted changes
    try:
        result = subprocess.run(
            ["git", "status", "--porcelain"],
            capture_output=True, text=True, cwd=repo_path
        )
        is_dirty = bool(result.stdout.strip())
    except Exception:
        is_dirty = True

    return f"{repo_id['commit']}_{'dirty' if is_dirty else 'clean'}"

def _get_fallback_tier(tier: Tier) -> Optional[Tier]:
    """Get fallback tier if primary fails."""
    fallbacks = {
        Tier.INSTANT: Tier.RAG,
        Tier.RAG: Tier.LONG_CONTEXT,
        Tier.LONG_CONTEXT: Tier.FLASH_DEEP,  # Escalate to larger context
        Tier.FLASH_DEEP: None,  # No fallback - maximum capacity
        Tier.PERPLEXITY: Tier.LONG_CONTEXT,  # Fall back to internal
        Tier.HYBRID: Tier.LONG_CONTEXT,
    }
    return fallbacks.get(tier)

def _should_use_truths(intent: QueryIntent, complexity: QueryComplexity) -> bool:
    """Determine if repo_truths.yaml should be checked first."""
    # COUNT queries always check truths
    if intent == QueryIntent.COUNT:
        return True

    # Simple queries might benefit from truths
    if complexity == QueryComplexity.SIMPLE:
        return intent in (QueryIntent.LOCATE, QueryIntent.EXPLAIN)

    return False

def _determine_sets(profile: QueryProfile, tier: Tier) -> List[str]:
    """Determine which analysis sets to use."""
    sets = []

    # Start with suggested sets from analyzer
    sets.extend(profile.suggested_sets)

    # Tier-specific adjustments
    if tier == Tier.RAG:
        # RAG works best with focused sets
        if not sets:
            sets = ["pipeline", "classifiers"]
    elif tier == Tier.LONG_CONTEXT:
        # Long context can handle larger sets
        if profile.intent == QueryIntent.TASK:
            # Task queries need full agent context
            sets = ["agent_full"] + [s for s in sets if not s.startswith("agent_")]
        elif profile.intent == QueryIntent.ARCHITECTURE:
            if "architecture_review" not in sets:
                sets.append("architecture_review")
    elif tier == Tier.FLASH_DEEP:
        # FLASH_DEEP: Load EVERYTHING - 2M context capacity
        # Include all major sets for comprehensive analysis
        comprehensive_sets = [
            "pipeline", "theory", "architecture_review",
            "agent_full", "visualization", "classifiers"
        ]
        # Start with comprehensive sets, add any suggested that aren't included
        sets = comprehensive_sets + [s for s in sets if s not in comprehensive_sets]

    # Ensure we have at least one set
    if not sets:
        sets = ["theory"]

    # NO CAP HERE - sanitize_sets() handles capping after alias/validation/dedup
    # Early capping here would drop valid sets when invalid ones crowd the front
    return sets

def _merge_sets_ordered(priority_sets: List[str], secondary_sets: List[str]) -> List[str]:
    """Merge two set lists, preserving order with priority_sets first.

    Note: This returns the RAW merged list. Sanitization happens separately
    via sanitize_sets() after all sets are collected.
    """
    seen = set()
    result = []
    for s in priority_sets:
        if s not in seen:
            seen.add(s)
            result.append(s)
    for s in secondary_sets:
        if s not in seen:
            seen.add(s)
            result.append(s)
    return result  # No cap here - sanitize_sets handles it

def format_routing_decision(decision: RoutingDecision) -> str:
    """Format routing decision for display."""
    lines = [
        f"Tier: {decision.tier.value.upper()}",
        f"Sets: {', '.join(decision.primary_sets)}",
        f"Context Flow: {decision.context_flow}",
        f"Reason: {decision.reasoning}",
    ]

    if decision.fallback_tier:
        lines.append(f"Fallback: {decision.fallback_tier.value}")
    if decision.use_truths:
        lines.append("Will check repo_truths.yaml first")
    if decision.inject_agent:
        lines.append("Agent context will be auto-injected")

    # Semantic matching details
    if decision.semantic:
        lines.append("")
        lines.append("Semantic Match:")
        if decision.semantic.targets:
            for t in decision.semantic.targets:
                parts = []
                if t.purpose:
                    parts.append(f"π₂={t.purpose}")
                if t.layer:
                    parts.append(f"layer={t.layer}")
                if t.roles:
                    parts.append(f"roles=[{','.join(t.roles[:2])}]")
                lines.append(f"  Target: {' '.join(parts)}")
        lines.append(f"  Traversal: {decision.traversal_direction.value}")

    return "\n".join(lines)

